#include<bits/stdc++.h>
using namespace std;
long long n,m,r,a[100005],l,ans;
bool check(long long x)
{
	ans=0;
	if(x==0)	return 0;
	for(int i=1;i<n;i++)
	{
		ans+=(a[i+1]-a[i]-1)/x;
	}
	return ans<=m;
}
int main()
{
	cin>>r>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	sort(a+1,a+1+n);
	l=0;
//	for(int i=45;i<=55;i++)
//	{
//		cout<<check(i)<<" "<<i<<"\n";
//	}
	while(l<r)
	{
		long long mid=l+(r-l)/2;
		if(check(mid))	r=mid;
		else	l=mid+1;
	}
	cout<<l;
	return 0;
}
